<script>
  document.getElementById('pbtn').addEventListener('click', function() {
    var passwordField = document.getElementById('ppass');
    var type = passwordField.getAttribute('type');
    if (type === 'password') {
        passwordField.setAttribute('type', 'text');
    } else {
        passwordField.setAttribute('type', 'password');
    }
});
document.getElementById('paybtn').addEventListener('click', function() {
    var passwordField = document.getElementById('paypass');
    var type = passwordField.getAttribute('type');
    if (type === 'password') {
        passwordField.setAttribute('type', 'text');
        // Optionally change the button icon to indicate that the password is visible
        this.querySelector('svg').setAttribute('viewBox', '0 0 24 24'); // Modify this line to update the icon
    } else {
        passwordField.setAttribute('type', 'password');
        // Optionally revert the button icon to indicate that the password is hidden
        this.querySelector('svg').setAttribute('viewBox', '0 0 24 24'); // Modify this line to update the icon
    }
});

  $(document).ready(function () {
    $('.submit').click(function () {
            var formData = $('#reg').serialize();          
                  $.ajax({
                  url: '{{ url("auth/register") }}',
                  type: 'POST',
                  data: formData,
                  dataType: 'json',
                  success: function(response) {
                      console.log(response); 
                      if(response.status == 'falses'){
                        $('.erros').html(response.message);
                        
                      }
                      if(response.status == false){
                        Swal.fire({
                          icon: 'error',
                          title: 'Error!',
                          text: response.message,
                          showConfirmButton: false,
                          timer: 2000 
                        });
                      }
                      if(response.status == true){
                       $('.erros').html('');
                       setTimeout(function () {
                          window.location.href = '{{ url("auth/login") }}';
                        }, 3000); 
                        Swal.fire({
                        icon: 'success',
                        title: 'Success!',
                        text: response.message,
                        showConfirmButton: false,
                        timer: 2000 
                        });
                    }
                  },
                  error: function(xhr, status, error) {
                      console.error(xhr.responseText);
                      // Handle error response
                  }
              });
          });
  })
</script>
